mapper.select:
SELECT a.*, c.name as class_name, col.name as college_name
FROM alumni a
LEFT JOIN class c ON a.class_id = c.id
LEFT JOIN college col ON c.college_id = col.id
WHERE a.deleted = 0

    AND a.name LIKE CONCAT('%', #{name}, '%')


    AND a.student_no LIKE CONCAT('%', #{studentNo}, '%')


    AND a.class_id = #{classId}


    AND c.college_id = #{collegeId}


    AND a.industry = #{industry}


    AND a.region = #{region}

ORDER BY a.create_time DESC
